UPDATE cms_pages SET meta_description = 'npm i @inneranimalmedia/agentsam-sdk — sandboxes, tools, and promote-only paths for Agent Sam.', seo_title = 'Agent Sam — @inneranimalmedia/agentsam-sdk', updated_at = unixepoch() WHERE id = '5de91aa0-10cc-45e5-9607-199d5c2f8467';
UPDATE cms_page_sections SET section_data = '{"html_source": "assembled", "html": "<section class=\"hero\" data-section-key=\"hero\" data-cms-section=\"hero\" data-section-type=\"hero\" aria-labelledby=\"hero-title\">\n        <div class=\"hero-grid\" aria-hidden=\"true\"></div>\n        <svg class=\"hero-lines\" viewBox=\"0 0 1050 360\" aria-hidden=\"true\" preserveAspectRatio=\"none\">\n          <defs>\n            <linearGradient id=\"lineFade\" x1=\"0\" x2=\"1\">\n              <stop offset=\"0\" stop-color=\"#7fc8ff\" stop-opacity=\"0.02\" />\n              <stop offset=\"0.36\" stop-color=\"#7fc8ff\" stop-opacity=\"0.48\" />\n              <stop offset=\"0.78\" stop-color=\"#1a94df\" stop-opacity=\"0.22\" />\n              <stop offset=\"1\" stop-color=\"#1a94df\" stop-opacity=\"0\" />\n            </linearGradient>\n          </defs>\n          <path d=\"M 50 36 C 172 150, 264 165, 368 178 S 693 180, 1050 180\" fill=\"none\" stroke=\"url(#lineFade)\" stroke-width=\"1\" />\n          <path d=\"M 50 74 C 164 150, 250 165, 368 178 S 693 180, 1050 180\" fill=\"none\" stroke=\"url(#lineFade)\" stroke-width=\"1\" />\n          <path d=\"M 50 112 C 154 154, 248 168, 368 178 S 693 180, 1050 180\" fill=\"none\" stroke=\"url(#lineFade)\" stroke-width=\"1\" />\n          <path d=\"M 50 150 C 156 168, 248 176, 368 178 S 693 180, 1050 180\" fill=\"none\" stroke=\"url(#lineFade)\" stroke-width=\"1\" />\n          <path d=\"M 50 180 C 162 180, 251 180, 368 178 S 693 180, 1050 180\" fill=\"none\" stroke=\"url(#lineFade)\" stroke-width=\"1\" />\n          <path d=\"M 50 210 C 162 190, 251 184, 368 178 S 693 180, 1050 180\" fill=\"none\" stroke=\"url(#lineFade)\" stroke-width=\"1\" />\n          <path d=\"M 50 248 C 164 206, 250 191, 368 178 S 693 180, 1050 180\" fill=\"none\" stroke=\"url(#lineFade)\" stroke-width=\"1\" />\n          <path d=\"M 50 286 C 172 210, 264 195, 368 178 S 693 180, 1050 180\" fill=\"none\" stroke=\"url(#lineFade)\" stroke-width=\"1\" />\n        </svg>\n        <div class=\"hero-orb\" aria-hidden=\"true\"></div>\n        <div class=\"hero-copy\">\n          <div class=\"eyebrow\"><i aria-hidden=\"true\"></i> @inneranimalmedia/agentsam-sdk</div>\n          <h1 id=\"hero-title\">Ship Agent Sam with a real SDK computer</h1>\n          <p>npm i @inneranimalmedia/agentsam-sdk — then give agents ephemeral sandboxes, scoped tools, terminals, and promote-only paths back into your Cloudflare stack.</p>\n          <div class=\"hero-actions\">\n            <a class=\"btn btn-primary\" href=\"#secure\">Install the SDK</a>\n            <a class=\"btn\" href=\"#observe\">See sandbox sessions</a>\n          </div>\n        </div>\n        <div class=\"orbit-strip\" aria-label=\"Capability metrics\">\n          <div class=\"metric\"><b>Ephemeral by default</b><span>agentsam-sdk sandboxed runs</span></div>\n          <div class=\"metric\"><b>Tool-aware access</b><span>BYOK + platform secret lanes</span></div>\n          <div class=\"metric\"><b>Parallel workers</b><span>parallel tool loops via SDK</span></div>\n          <div class=\"metric\"><b>Persistent sessions</b><span>session state the SDK can resume</span></div>\n        </div>\n      </section>", "r2_key": "pages/agentsam/sections/hero.html"}', updated_at = unixepoch() WHERE id = 'sec_agentsam_hero';
UPDATE cms_page_sections SET section_data = '{"html_source": "assembled", "html": "<section class=\"section\" id=\"scale\" data-section-key=\"scale\" data-cms-section=\"scale\" data-section=\"scale\" aria-labelledby=\"scale-title\">\n          <div class=\"section-copy\">\n            <h2 id=\"scale-title\">From npm install to an agent fleet</h2>\n            <p class=\"section-lead\">The SDK is how products wire Agent Sam: import the client, attach tools, and open sandboxes for codegen, tests, browser research, and repo inspection without inventing a new agent runtime.</p>\n            <div class=\"feature-list\">\n              <article class=\"feature\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke-width=\"1.5\" aria-hidden=\"true\"><path d=\"m13 2-9 12h7l-1 8 10-13h-7l1-7Z\"/></svg>\n                <div><h3>One package, many agent workers</h3><p>Fan out audits, evals, migrations, and build attempts from the same @inneranimalmedia/agentsam-sdk entrypoint your dashboard already uses.</p></div>\n              </article>\n              <article class=\"feature\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke-width=\"1.5\" aria-hidden=\"true\"><path d=\"m12 3 8 4.5v9L12 21l-8-4.5v-9L12 3Z\"/><path d=\"M12 12 4 7.5\"/><path d=\"M12 12v9\"/><path d=\"m12 12 8-4.5\"/></svg>\n                <div><h3>Bring your own stack</h3><p>Pin Node, Python, ffmpeg, browsers, and repo-specific deps in the sandbox image while the SDK keeps credentials on policy rails.</p></div>\n              </article>\n            </div>\n          </div>\n\n          <div class=\"mock-wrap\">\n            <article class=\"mock-card\" aria-label=\"Create sandbox mockup\">\n              <div class=\"mock-top\">\n                <div class=\"mock-title\">SDK sandbox request</div>\n                <span class=\"chip purple\">agentsam-sdk</span>\n              </div>\n              <div class=\"mock-body\">\n                <div class=\"form-grid\">\n                  <div class=\"field full\"><label>Snapshot</label><input value=\"@inneranimalmedia/agentsam-sdk@1.x\" aria-label=\"Snapshot\" /></div>\n                  <div class=\"field\"><label>vCPUs</label><input value=\"4\" aria-label=\"vCPUs\" /></div>\n                  <div class=\"field\"><label>Memory (MiB)</label><input value=\"4096\" aria-label=\"Memory\" /></div>\n                  <div class=\"field full\"><label>Name</label><input value=\"sdk-run--inneranimalmedia\" aria-label=\"Name\" /></div>\n                  <div class=\"field\"><label>TTL</label><input value=\"60 min\" aria-label=\"TTL\" /></div>\n                  <div class=\"field\"><label>Idle TTL</label><input value=\"8 min\" aria-label=\"Idle TTL\" /></div>\n                </div>\n                <div class=\"rule-row\">\n                  <span>Proxy Rules</span>\n                  <button class=\"add-rule\" type=\"button\">+ Add Rule</button>\n                </div>\n                <div class=\"field\"><label>Access Control</label><select aria-label=\"Access control\"><option>agentsam-sdk tool policy</option><option>Read-only filesystem</option><option>No external network</option></select></div>\n              </div>\n            </article>\n          </div>\n        </section>", "r2_key": "pages/agentsam/sections/scale.html"}', updated_at = unixepoch() WHERE id = 'sec_agentsam_scale';
UPDATE cms_page_sections SET section_data = '{"html_source": "assembled", "html": "<section class=\"section\" id=\"state\" data-section-key=\"state\" data-cms-section=\"state\" data-section=\"state\" aria-labelledby=\"state-title\">\n          <div class=\"section-copy\">\n            <h2 id=\"state-title\">Sessions the SDK can actually resume</h2>\n            <p class=\"section-lead\">Agent Sam sessions stream over the control plane the SDK talks to — keep state across turns, tunnel previews, then tear down when the job is done.</p>\n            <div class=\"feature-list\">\n              <article class=\"feature\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke-width=\"1.5\" aria-hidden=\"true\"><path d=\"M6 3h12\"/><path d=\"M6 21h12\"/><path d=\"M8 3c0 5 8 5 8 9s-8 4-8 9\"/><path d=\"M16 3c0 5-8 5-8 9s8 4 8 9\"/></svg>\n                <div><h3>Configurable TTLs</h3><p>Expire idle sessions automatically so SDK experiments stay cheap and do not become surprise infrastructure.</p></div>\n              </article>\n              <article class=\"feature\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke-width=\"1.5\" aria-hidden=\"true\"><path d=\"M6 3v18\"/><path d=\"M18 6v12\"/><circle cx=\"6\" cy=\"6\" r=\"2\"/><circle cx=\"18\" cy=\"18\" r=\"2\"/><path d=\"M6 8c0 4 12 2 12 8\"/></svg>\n                <div><h3>Snapshot and fork</h3><p>Snapshot a sandbox the SDK opened, restore it later, or fork alternatives so agents explore safely in parallel.</p></div>\n              </article>\n              <article class=\"feature\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke-width=\"1.5\" aria-hidden=\"true\"><path d=\"M4 8h10a4 4 0 0 1 0 8H9\"/><path d=\"m7 12-3-4 3-4\"/><path d=\"M20 16H10a4 4 0 0 1 0-8h5\"/><path d=\"m17 12 3 4-3 4\"/></svg>\n                <div><h3>Port tunneling</h3><p>Tunnel a preview the SDK opened — app, API, or build — without exposing the whole machine.</p></div>\n              </article>\n            </div>\n          </div>\n\n          <div class=\"mock-wrap\">\n            <article class=\"mock-card wide\" aria-label=\"Live terminal mockup\">\n              <div class=\"terminal-shell\">\n                <aside class=\"app-rail\">\n                  <strong>agentsam-sdk</strong>\n                  <div class=\"rail-menu\">\n                    <span><i></i> All applications</span>\n                    <span><i></i> Search</span>\n                    <span><i></i> Home</span>\n                    <span><i></i> Tracing</span>\n                    <span><i></i> Monitoring</span>\n                    <span><i></i> Datasets &amp; evals</span>\n                    <span><i></i> Prompts</span>\n                    <span><i></i> Studio</span>\n                  </div>\n                </aside>\n                <div class=\"terminal-area\">\n                  <div class=\"terminal-head\">\n                    <h4>sandbox-8530bec8</h4>\n                    <div class=\"mock-actions\"><span class=\"chip ready\">READY</span><span class=\"chip purple\">Open tunnel</span></div>\n                  </div>\n                  <div class=\"terminal-window\">\n                    <div class=\"terminal-tab\">Terminal</div>\n                    <pre class=\"terminal-output\" id=\"terminalOutput\"><span class=\"prompt\">root@agentsam:~#</span> <span class=\"command\">uname &amp;&amp; node -v</span>\nLinux\nv22.11.0\n<span class=\"prompt\">root@agentsam:~#</span> <span class=\"command\">npm i @inneranimalmedia/agentsam-sdk && agentsam --version</span>\n<span class=\"ok\">✓</span> auth proxy policy validated\n<span class=\"ok\">✓</span> worker bindings mocked\n<span class=\"ok\">✓</span> preview tunnel listening on :8787\n<span class=\"muted\">streaming logs to Agent Sam control plane...</span></pre>\n                  </div>\n                </div>\n              </div>\n            </article>\n          </div>\n        </section>", "r2_key": "pages/agentsam/sections/state.html"}', updated_at = unixepoch() WHERE id = 'sec_agentsam_state';
